 1→import { useState, useEffect, useCallback } from "react";
 2→import { invoke } from "@tauri-apps/api/core";
 3→import type { SessionInfo } from "../types";
 4→import { useTauriEvent } from "./useTauriEvent";
 5→
 6→interface PickerState {
 7→  sessions: SessionInfo[];
 8→  loading: boolean;
 9→  searchQuery: string;
10→}
11→
12→export function usePicker(selectedProject: string | null = null) {
13→  const [state, setState] = useState<PickerState>({
14→    sessions: [],
15→    loading: false,
16→    searchQuery: "",
17→  });
18→
19→  const discoverSessions = useCallback(async (projectDirs: string[]) => {
20→    setState((prev) => ({ ...prev, loading: true }));
21→    try {
22→      const sessions = await invoke<SessionInfo[]>("discover_sessions", {
23→        projectDirs,
24→      });
25→      setState((prev) => ({ ...prev, sessions, loading: false }));
26→
27→      // Start watching for new sessions
28→      try {
29→        await invoke<void>("watch_picker", { projectDirs });
30→      } catch {
31→        // watcher is optional
32→      }
33→    } catch (err) {
34→      console.error("Failed to discover sessions:", err);
35→      setState((prev) => ({ ...prev, loading: false }));
36→    }
37→  }, []);
38→
39→  const setSearchQuery = useCallback((query: string) => {
40→    setState((prev) => ({ ...prev, searchQuery: query }));
41→  }, []);
42→
43→  /** Sync ongoing status from the session watcher into the picker list. */
44→  const syncOngoing = useCallback((sessionPath: string, ongoing: boolean) => {
45→    setState((prev) => {
46→      const idx = prev.sessions.findIndex((s) => s.path === sessionPath);
47→      if (idx === -1 || prev.sessions[idx].is_ongoing === ongoing) return prev;
48→      const sessions = [...prev.sessions];
49→      sessions[idx] = { ...sessions[idx], is_ongoing: ongoing };
50→      return { ...prev, sessions };
51→    });
52→  }, []);
53→
54→  // Listen for picker-refresh events (backend already applies staleness)
55→  useTauriEvent<{ sessions: SessionInfo[] }>("picker-refresh", (payload) => {
56→    setState((prev) => ({
57→      ...prev,
58→      sessions: payload.sessions,
59→    }));
60→  });
61→
62→  // Cleanup on unmount
63→  useEffect(() => {
64→    return () => {
65→      invoke<void>("unwatch_picker").catch(() => {});
66→    };
67→  }, []);
68→
69→  // Filter sessions by search query
70→  let filteredSessions = state.searchQuery
71→    ? state.sessions.filter(
72→        (s) =>
73→          s.first_message.toLowerCase().includes(state.searchQuery.toLowerCase()) ||
74→          s.session_id.toLowerCase().includes(state.searchQuery.toLowerCase()) ||
75→          s.model.toLowerCase().includes(state.searchQuery.toLowerCase()),
76→      )
77→    : state.sessions;
78→
79→  // Filter by selected project
80→  if (selectedProject) {
81→    filteredSessions = filteredSessions.filter((s) =>
82→      s.path.replace(/\\/g, "/").includes(`/.claude/projects/${selectedProject}/`),
83→    );
84→  }
85→
86→  return {
87→    sessions: filteredSessions,
88→    allSessions: state.sessions,
89→    loading: state.loading,
90→    searchQuery: state.searchQuery,
91→    setSearchQuery,
92→    discoverSessions,
93→    syncOngoing,
94→  };
95→}
