 10→/// Maximum time since last file modification before a session is dead.
 11→pub const ONGOING_STALENESS_THRESHOLD: Duration = Duration::from_secs(60);
 12→
 13→/// Returns true if the session is still ongoing (not stale).
 14→/// Returns false if `is_ongoing` is false, or if `mod_time` exceeds the staleness threshold.
 15→pub fn apply_staleness(is_ongoing: bool, mod_time: impl Into<DateTime<Utc>>) -> bool {
 16→    if !is_ongoing {
 17→        return false;
 18→    }
 19→    let elapsed = Utc::now()
 20→        .signed_duration_since(mod_time.into())
 21→        .to_std()
 22→        .unwrap_or(Duration::ZERO);
 23→    elapsed <= ONGOING_STALENESS_THRESHOLD
 24→}
