 79→    let signal_tx_clone = signal_tx.clone();
 80→
 81→    // Spawn the file watcher thread (notify requires std thread).
 82→    std::thread::spawn(move || {
 83→        let signal_tx = signal_tx_clone;
 84→        let path = path_clone;
 85→
 86→        let (tx, rx) = std::sync::mpsc::channel();
 87→        let mut watcher = match RecommendedWatcher::new(tx, Config::default()) {
 88→            Ok(w) => w,
 89→            Err(_) => return,
 90→        };
 91→
 92→        // Watch the session file.
 93→        let _ = watcher.watch(Path::new(&path), RecursiveMode::NonRecursive);
 94→
 95→        // Watch the project directory for new team session files.
 96→        let project_dir = Path::new(&path).parent().unwrap_or(Path::new(""));
 97→        let _ = watcher.watch(project_dir, RecursiveMode::NonRecursive);
 98→
 99→        // Watch the subagents directory so ongoing dot updates quickly.
100→        let subagents_dir = crate::parser::subagent::subagents_dir(&path);
101→        if subagents_dir.exists() {
102→            let _ = watcher.watch(&subagents_dir, RecursiveMode::NonRecursive);
103→        }
104→
105→        run_debounce_loop(
106→            rx,
107→            |event| {
108→                event.paths.iter().any(|p| {
109→                    p.to_string_lossy() == path
110→                        || p.extension().map(|e| e == "jsonl").unwrap_or(false)
111→                })
112→            },
113→            signal_tx,
114→        );
115→    });
116→
117→    // Spawn the async rebuild loop.
118→    let path_for_rebuild = path.clone();
119→    tauri::async_runtime::spawn(async move {
120→        let mut all_classified = initial_classified;
121→        let mut offset = initial_offset;
122→        let mut token_scanner = IncrementalTokenScanner::new();
123→        let mut prev_msg_count: usize = 0;
124→        let mut prev_ongoing = false;
125→
126→        // Seed the token scanner with the initial file content.
127→        token_scanner.scan_new_bytes(&path_for_rebuild);
128→
129→        loop {
130→            tokio::select! {
131→                _ = stop_rx.recv() => {
132→                    break;
133→                }
134→                Some(()) = signal_rx.recv() => {
135→                    // Read any new data.
136→                    match read_session_incremental(&path_for_rebuild, offset) {
137→                        Ok((new_msgs, new_offset, _)) => {
138→                            if !new_msgs.is_empty() || new_offset != offset {
139→                                offset = new_offset;
140→                                all_classified.extend(new_msgs);
141→                            }
142→                        }
143→                        Err(_) => continue,
144→                    }
145→
146→                    let mut chunks = build_chunks(&all_classified);
147→
148→                    let (mut all_procs, color_map) = discover_and_link_all(&path_for_rebuild, &chunks);
149→                    inject_orphan_subagents(&mut chunks, &mut all_procs);
150→
151→                    let ongoing = OngoingChecker::new(&chunks, &all_procs, &path_for_rebuild).is_ongoing();
152→
153→                    let teams = reconstruct_teams(&chunks, &all_procs);
154→                    let messages = chunks_to_messages(&chunks, &all_procs, &color_map);
155→
156→                    // Skip emit if nothing meaningful changed.
157→                    let msg_count = messages.len();
158→                    if msg_count == prev_msg_count && !ongoing && !prev_ongoing {
159→                        // Token totals may still have changed — update scanner
160→                        // but skip the expensive emit + serialize.
161→                        token_scanner.scan_new_bytes(&path_for_rebuild);
162→                        continue;
163→                    }
164→                    prev_msg_count = msg_count;
165→                    prev_ongoing = ongoing;
166→
167→                    // Extract last permission_mode from UserMsg entries.
168→                    let mut permission_mode = String::from("default");
169→                    for msg in all_classified.iter().rev() {
170→                        if let ClassifiedMsg::User(u) = msg {
171→                            if !u.permission_mode.is_empty() {
172→                                permission_mode = u.permission_mode.clone();
173→                                break;
174→                            }
175→                        }
176→                    }
177→
178→                    // Incrementally scan only new bytes for token totals.
179→                    let session_totals = token_scanner.scan_new_bytes(&path_for_rebuild);
180→
181→                    let payload = SessionUpdatePayload {
182→                        messages,
183→                        teams,
184→                        ongoing,
185→                        permission_mode,
186→                        session_totals,
187→                    };
188→
189→                    let _ = app.emit("session-update", payload);
190→                }
191→            }
192→        }
193→    });
194→
195→    WatcherHandle { stop_tx }
196→}
