        env::remove_var("CLAUDE_PROJECTS_DIR");
        std::fs::remove_dir_all(&tmp_configured).ok();
        std::fs::remove_dir_all(&tmp_env).ok();
    }

    #[test]
    fn claude_projects_dir_falls_back_when_env_path_missing() {
        env::set_var(
            "CLAUDE_PROJECTS_DIR",
            "/nonexistent/path/that/does/not/exist",
        );
