 1→import { useRef, useEffect, type RefObject } from "react";
 2→
 3→/**
 4→ * Auto-scrolls a container to the bottom when `itemCount` increases,
 5→ * but only if the user is already near the bottom (within `threshold` px).
 6→ * Optionally accepts an existing ref to attach to instead of creating a new one.
 7→ */
 8→export function useAutoScroll<T extends HTMLElement>(
 9→  itemCount: number,
10→  existingRef?: RefObject<T | null>,
11→  threshold = 150,
12→) {
13→  const ownRef = useRef<T>(null);
14→  const ref = existingRef ?? ownRef;
15→  const prevCountRef = useRef(itemCount);
16→
17→  useEffect(() => {
18→    const el = ref.current;
19→    if (el && itemCount > prevCountRef.current) {
20→      const isNearBottom = el.scrollHeight - el.scrollTop - el.clientHeight < threshold;
21→      if (isNearBottom) {
22→        el.scrollTop = el.scrollHeight;
23→      }
24→    }
25→    prevCountRef.current = itemCount;
26→  }, [itemCount, threshold, ref]);
27→
28→  return ref;
29→}
