 8→  Object.defineProperty(el, "scrollHeight", { value: scrollHeight, configurable: true });
 9→  Object.defineProperty(el, "scrollTop", { value: scrollTop, writable: true, configurable: true });
10→  Object.defineProperty(el, "clientHeight", { value: clientHeight, configurable: true });
11→  return el;
12→}
