  1→import { useState, useMemo, useCallback, useRef, useLayoutEffect } from "react";
  2→import ReactMarkdown from "react-markdown";
  3→import type { DisplayMessage, DisplayItem } from "../types";
  4→import { shortModel, formatTokens, formatDuration, formatExactTime } from "../lib/format";
  5→import { getModelColor, getTeamColor } from "../lib/theme";
  6→import { MessageItem } from "./MessageItem";
  7→import { DetailItem } from "./DetailItem";
  8→import { useToggleSet } from "../hooks/useToggleSet";
  9→import { useScrollToSelected } from "../hooks/useScrollToSelected";
 10→import { useAutoScroll } from "../hooks/useAutoScroll";
 11→import { useKeyboard } from "../hooks/useKeyboard";
 12→import { BackButton } from "./BackButton";
 13→import { ResizeHandle } from "./ResizeHandle";
 14→import { OngoingDots } from "./OngoingDots";
 15→import { IoMdCloseCircle } from "react-icons/io";
 16→import { ClaudeIcon } from "./Icons";
 17→
 18→/* ─── Panel stack types ─── */
 19→
 20→type PanelEntry =
 21→  | { kind: "agent-list"; item: DisplayItem; key: string }
 22→  | { kind: "agent-detail"; item: DisplayItem; msg: DisplayMessage; key: string };
 23→
 24→/** Imperative handle exposed by each navigable column */
 25→interface ColumnNav {
 26→  moveUp: () => void;
 27→  moveDown: () => void;
 28→  toggle: () => void;
 29→  enter: () => void;
 30→  itemCount: () => number;
 31→}
 32→
 33→interface MessageDetailProps {
 34→  message: DisplayMessage;
 35→  ongoing?: boolean;
 36→  onBack: () => void;
 37→}
 38→
 39→export function MessageDetail({ message: msg, ongoing, onBack }: MessageDetailProps) {
 40→  const { set: expandedItems, toggle: toggleItem } = useToggleSet();
 41→  const [selectedItem, setSelectedItem] = useState(0);
 42→  const scrollRef = useScrollToSelected(selectedItem);
 43→  const [panelStack, setPanelStack] = useState<PanelEntry[]>([]);
 44→  const [columnWidths, setColumnWidths] = useState<(number | null)[]>([null]);
 45→  const [focusedColumn, setFocusedColumn] = useState(0); // 0 = main, 1+ = panel index + 1
 46→  const bodyRef = useRef<HTMLDivElement>(null);
 47→  useAutoScroll(msg.items.length, bodyRef);
 48→  const savedScroll = useRef<number | null>(null);
 49→  const panelRefs = useRef<Map<number, ColumnNav>>(new Map());
 50→
 51→  useLayoutEffect(() => {
 52→    if (savedScroll.current != null && bodyRef.current) {
 53→      bodyRef.current.scrollTop = savedScroll.current;
 54→      savedScroll.current = null;
 55→    }
 56→  }, [panelStack.length]);
 57→
 58→  const model = msg.model ? shortModel(msg.model) : "";
 59→  const modelColor = msg.model ? getModelColor(msg.model) : undefined;
 60→  const time = formatExactTime(msg.timestamp);
 61→  const hasItems = msg.items.length > 0;
 62→  const hasPanels = panelStack.length > 0;
 63→
 64→  // Stack manipulation
 65→  const openSubagentFromMain = useCallback((item: DisplayItem) => {
 66→    if (bodyRef.current) {
 67→      savedScroll.current = bodyRef.current.scrollTop;
 68→    }
 69→    setPanelStack((prev) => {
 70→      if (
 71→        prev.length === 1 &&
 72→        prev[0].kind === "agent-list" &&
 73→        prev[0].item.agent_id === item.agent_id
 74→      ) {
 75→        return [];
 76→      }
 77→      return [{ kind: "agent-list", item, key: item.agent_id || `panel-0` }];
 78→    });
 79→    setColumnWidths((prev) => [prev[0]]);
 80→    setFocusedColumn(1);
 81→  }, []);
 82→
 83→  const openSubagentAt = useCallback((depth: number, item: DisplayItem) => {
 84→    setPanelStack((prev) => {
 85→      const next = prev.slice(0, depth + 1);
 86→      next.push({ kind: "agent-list", item, key: item.agent_id || `panel-${depth + 1}` });
 87→      return next;
 88→    });
 89→    setColumnWidths((prev) => prev.slice(0, depth + 2));
 90→    setFocusedColumn(depth + 2);
 91→  }, []);
 92→
 93→  const openDetailAt = useCallback((depth: number, detailMsg: DisplayMessage) => {
 94→    setPanelStack((prev) => {
 95→      const entry = prev[depth];
 96→      if (!entry || entry.kind !== "agent-list") return prev;
 97→      const next = prev.slice(0, depth);
 98→      next.push({
 99→        kind: "agent-detail",
100→        item: entry.item,
101→        msg: detailMsg,
102→        key: entry.key + ":detail",
103→      });
104→      return next;
105→    });
106→  }, []);
107→
108→  const backToListAt = useCallback((depth: number) => {
109→    setPanelStack((prev) => {
110→      const entry = prev[depth];
111→      if (!entry || entry.kind !== "agent-detail") return prev;
112→      const next = prev.slice(0, depth);
113→      next.push({
114→        kind: "agent-list",
115→        item: entry.item,
116→        key: entry.item.agent_id || `panel-${depth}`,
117→      });
118→      return next;
119→    });
120→  }, []);
121→
122→  const closeAt = useCallback((depth: number) => {
123→    setPanelStack((prev) => prev.slice(0, depth));
124→    setColumnWidths((prev) => prev.slice(0, depth + 1));
125→    setFocusedColumn((prev) => Math.min(prev, depth));
126→  }, []);
127→
128→  const setColumnWidth = useCallback((colIndex: number, width: number) => {
129→    setColumnWidths((prev) => {
130→      const next = [...prev];
131→      while (next.length <= colIndex) next.push(null);
132→      next[colIndex] = width;
133→      return next;
134→    });
135→  }, []);
136→
137→  const handleItemClick = (index: number, item: DisplayItem) => {
138→    setSelectedItem(index);
139→    setFocusedColumn(0);
140→    if (item.subagent_messages.length > 0) {
141→      openSubagentFromMain(item);
142→    } else {
143→      toggleItem(index);
144→    }
145→  };
146→
147→  const registerPanelNav = useCallback((depth: number, nav: ColumnNav | null) => {
148→    if (nav) {
149→      panelRefs.current.set(depth, nav);
150→    } else {
151→      panelRefs.current.delete(depth);
152→    }
153→  }, []);
154→
155→  // Single keyboard handler for all columns
156→  const detailKeyMap: Record<string, () => void> = {};
157→
158→  // Navigation: j/k/ArrowDown/ArrowUp/Tab/Enter dispatch to the focused column
159→  const moveDown = () => {
160→    if (focusedColumn === 0) {
161→      setSelectedItem((i) => Math.min(i + 1, msg.items.length - 1));
162→    } else {
163→      const nav = panelRefs.current.get(focusedColumn - 1);
164→      nav?.moveDown();
165→    }
166→  };
167→  const moveUp = () => {
168→    if (focusedColumn === 0) {
169→      setSelectedItem((i) => Math.max(i - 1, 0));
170→    } else {
171→      const nav = panelRefs.current.get(focusedColumn - 1);
172→      nav?.moveUp();
173→    }
174→  };
175→  detailKeyMap["j"] = moveDown;
176→  detailKeyMap["ArrowDown"] = moveDown;
177→  detailKeyMap["k"] = moveUp;
178→  detailKeyMap["ArrowUp"] = moveUp;
179→  detailKeyMap["Tab"] = () => {
180→    if (focusedColumn === 0) {
181→      const item = msg.items[selectedItem];
182→      if (item) handleItemClick(selectedItem, item);
183→    } else {
184→      const nav = panelRefs.current.get(focusedColumn - 1);
185→      nav?.toggle();
186→    }
187→  };
188→  detailKeyMap["Enter"] = () => {
189→    if (focusedColumn === 0) {
190→      const item = msg.items[selectedItem];
191→      if (item && item.subagent_messages.length > 0) {
192→        openSubagentFromMain(item);
193→      } else if (item) {
194→        toggleItem(selectedItem);
195→      }
196→    } else {
197→      const nav = panelRefs.current.get(focusedColumn - 1);
198→      nav?.enter();
199→    }
200→  };
201→
202→  // h/l or ArrowLeft/ArrowRight to switch focused column
203→  detailKeyMap["h"] = () => setFocusedColumn((c) => Math.max(0, c - 1));
204→  detailKeyMap["ArrowLeft"] = () => setFocusedColumn((c) => Math.max(0, c - 1));
205→  detailKeyMap["l"] = () => setFocusedColumn((c) => Math.min(panelStack.length, c + 1));
206→  detailKeyMap["ArrowRight"] = () => setFocusedColumn((c) => Math.min(panelStack.length, c + 1));
207→
208→  // q = go back to list
209→  detailKeyMap["q"] = onBack;
210→  // Escape = close rightmost panel, or go back
211→  detailKeyMap["Escape"] = () => {
212→    if (panelStack.length > 0) {
213→      closeAt(panelStack.length - 1);
214→    } else {
215→      onBack();
216→    }
217→  };
218→
219→  useKeyboard(detailKeyMap);
220→
221→  const mainWidthStyle =
222→    hasPanels && columnWidths[0]
223→      ? { flex: `0 0 ${columnWidths[0]}px`, maxWidth: columnWidths[0] }
224→      : undefined;
225→
226→  return (
227→    <div className={`message-detail${hasPanels ? " message-detail--split" : ""}`}>
228→      <div
229→        className={`message-detail__main${focusedColumn === 0 ? " message-detail__main--focused" : ""}`}
230→        style={mainWidthStyle}
231→        onClick={() => setFocusedColumn(0)}
232→      >
233→        <div className="message-detail__header">
234→          <BackButton onClick={onBack} />
235→          <span className="message-detail__title">
236→            {msg.role === "user" ? "User" : msg.role === "claude" ? "Claude" : "System"}
237→          </span>
238→          {model && (
239→            <span style={{ color: modelColor, fontWeight: 600, fontSize: 12 }}>{model}</span>
240→          )}
241→          {msg.subagent_label && (
242→            <span className="detail-item__subagent-badge">{msg.subagent_label}</span>
243→          )}
244→          <span className="message-detail__meta">
245→            {time}
246→            {msg.tokens_raw > 0 && (
247→              <>
248→                {" "}
249→                {"\u00B7"} {formatTokens(msg.tokens_raw)} tok
250→              </>
251→            )}
252→            {msg.duration_ms > 0 && (
253→              <>
254→                {" "}
255→                {"\u00B7"} {formatDuration(msg.duration_ms)}
256→              </>
257→            )}
258→          </span>
259→        </div>
260→
261→        <div className="message-detail__body" ref={bodyRef}>
262→          <div className="message-detail__content">
263→            {msg.content && (
264→              <div className="message-detail__text">
265→                <ReactMarkdown>{msg.content}</ReactMarkdown>
266→              </div>
267→            )}
268→            {hasItems && (
269→              <div className="detail-items">
270→                <div className="detail-items__section-label">Items ({msg.items.length})</div>
271→                {msg.items.map((item, idx) => (
272→                  <DetailItem
273→                    key={`${item.item_type}-${item.tool_name}-${item.tool_summary}-${item.duration_ms}`}
274→                    ref={idx === selectedItem ? scrollRef : undefined}
275→                    item={item}
276→                    index={idx}
277→                    isSelected={idx === selectedItem}
278→                    isExpanded={expandedItems.has(idx)}
279→                    isAgentActive={
280→                      panelStack.length > 0 &&
281→                      panelStack[0].item.agent_id === item.agent_id &&
282→                      !!item.agent_id
283→                    }
284→                    onToggle={handleItemClick}
285→                    onToggleExpand={toggleItem}
286→                    onSelect={setSelectedItem}
287→                  />
288→                ))}
289→              </div>
290→            )}
291→            {ongoing && (
292→              <div className="message-detail__ongoing">
293→                <OngoingDots />
294→              </div>
295→            )}
296→          </div>
297→        </div>
298→      </div>
299→
300→      {panelStack.map((entry, depth) => {
301→        const colWidth = columnWidths[depth + 1];
302→        const widthStyle = colWidth ? { flex: `0 0 ${colWidth}px`, maxWidth: colWidth } : undefined;
303→        const isFocused = focusedColumn === depth + 1;
304→
305→        return (
306→          <PanelColumn
307→            key={entry.key}
308→            entry={entry}
309→            depth={depth}
310→            style={widthStyle}
311→            isFocused={isFocused}
312→            panelStack={panelStack}
313→            onOpenDetail={(detailMsg) => openDetailAt(depth, detailMsg)}
314→            onBackToList={() => backToListAt(depth)}
315→            onOpenSubagent={(item) => openSubagentAt(depth, item)}
316→            onClose={() => closeAt(depth)}
317→            onResize={(w) => setColumnWidth(depth, w)}
318→            onFocus={() => setFocusedColumn(depth + 1)}
319→            onRegisterNav={(nav) => registerPanelNav(depth, nav)}
320→          />
321→        );
322→      })}
323→    </div>
324→  );
325→}
