327→/* ─── PanelColumn: renders ResizeHandle + either list or detail ─── */
328→
329→interface PanelColumnProps {
330→  entry: PanelEntry;
331→  depth: number;
332→  style?: React.CSSProperties;
333→  isFocused: boolean;
334→  panelStack: PanelEntry[];
335→  onOpenDetail: (msg: DisplayMessage) => void;
336→  onBackToList: () => void;
337→  onOpenSubagent: (item: DisplayItem) => void;
338→  onClose: () => void;
339→  onResize: (width: number) => void;
340→  onFocus: () => void;
341→  onRegisterNav: (nav: ColumnNav | null) => void;
342→}
343→
344→function PanelColumn({
345→  entry,
346→  depth,
347→  style,
348→  isFocused,
349→  panelStack,
350→  onOpenDetail,
351→  onBackToList,
352→  onOpenSubagent,
353→  onClose,
354→  onResize,
355→  onFocus,
356→  onRegisterNav,
357→}: PanelColumnProps) {
358→  return (
359→    <>
360→      <ResizeHandle onResize={onResize} />
361→      {entry.kind === "agent-list" ? (
362→        <AgentListColumn
363→          item={entry.item}
364→          style={style}
365→          isFocused={isFocused}
366→          onOpenDetail={onOpenDetail}
367→          onClose={onClose}
