370→        />
371→      ) : (
372→        <AgentDetailColumn
373→          item={entry.item}
374→          msg={entry.msg}
375→          style={style}
376→          isFocused={isFocused}
377→          depth={depth}
378→          panelStack={panelStack}
379→          onOpenSubagent={onOpenSubagent}
380→          onBack={onBackToList}
381→          onClose={onClose}
382→          onFocus={onFocus}
383→          onRegisterNav={onRegisterNav}
384→        />
385→      )}
386→    </>
