390→/* ─── AgentListColumn: shows agent header + message list ─── */
391→
392→interface AgentListColumnProps {
393→  item: DisplayItem;
394→  style?: React.CSSProperties;
395→  isFocused: boolean;
396→  onOpenDetail: (msg: DisplayMessage) => void;
397→  onClose: () => void;
398→  onFocus: () => void;
399→  onRegisterNav: (nav: ColumnNav | null) => void;
400→}
401→
402→function AgentListColumn({
403→  item,
404→  style,
405→  isFocused,
406→  onOpenDetail,
407→  onClose,
408→  onFocus,
409→  onRegisterNav,
410→}: AgentListColumnProps) {
411→  const messages = item.subagent_messages;
412→  const [selectedMsg, setSelectedMsg] = useState(messages.length - 1);
413→  const { set: expandedSet, toggle: toggleMsg } = useToggleSet();
414→  const listRef = useAutoScroll<HTMLDivElement>(messages.length);
415→  const selectedRef = useScrollToSelected(selectedMsg);
416→  const panelColor = item.team_color ? getTeamColor(item.team_color) : undefined;
417→
418→  const handleClick = useCallback(
419→    (index: number) => {
420→      onFocus();
421→      if (selectedMsg === index) {
422→        toggleMsg(index);
423→      } else {
424→        setSelectedMsg(index);
425→      }
426→    },
427→    [selectedMsg, toggleMsg, onFocus],
428→  );
429→
430→  // Expose navigation to parent via callback ref
431→  const navRef = useRef<ColumnNav>({
432→    moveUp: () => setSelectedMsg((i) => Math.max(i - 1, 0)),
433→    moveDown: () => setSelectedMsg((i) => Math.min(i + 1, messages.length - 1)),
434→    toggle: () => toggleMsg(selectedMsg),
435→    enter: () => {
436→      if (messages[selectedMsg]) onOpenDetail(messages[selectedMsg]);
437→    },
438→    itemCount: () => messages.length,
439→  });
440→  navRef.current.moveUp = () => setSelectedMsg((i) => Math.max(i - 1, 0));
441→  navRef.current.moveDown = () => setSelectedMsg((i) => Math.min(i + 1, messages.length - 1));
442→  navRef.current.toggle = () => toggleMsg(selectedMsg);
443→  navRef.current.enter = () => {
444→    if (messages[selectedMsg]) onOpenDetail(messages[selectedMsg]);
445→  };
446→  navRef.current.itemCount = () => messages.length;
447→
448→  // Register/unregister nav on mount/unmount
449→  useLayoutEffect(() => {
450→    onRegisterNav(navRef.current);
451→    return () => onRegisterNav(null);
452→  }, [onRegisterNav]);
453→
454→  const ordered = useMemo(() => {
455→    const indices: number[] = [];
456→    for (let i = 0; i < messages.length; i++) indices.push(i);
457→    return indices;
458→  }, [messages.length]);
459→
460→  return (
461→    <div
462→      className={`agent-panel${isFocused ? " agent-panel--focused" : ""}`}
463→      style={
464→        {
465→          ...(panelColor ? { background: `${panelColor}08` } : {}),
