511→
512→interface AgentDetailColumnProps {
513→  item: DisplayItem;
514→  msg: DisplayMessage;
515→  style?: React.CSSProperties;
516→  isFocused: boolean;
517→  depth: number;
518→  panelStack: PanelEntry[];
519→  onOpenSubagent: (item: DisplayItem) => void;
520→  onBack: () => void;
521→  onClose: () => void;
522→  onFocus: () => void;
523→  onRegisterNav: (nav: ColumnNav | null) => void;
524→}
525→
526→function AgentDetailColumn({
527→  item,
528→  msg,
529→  style,
530→  isFocused,
531→  depth,
532→  panelStack,
533→  onOpenSubagent,
534→  onBack,
535→  onClose,
536→  onFocus,
537→  onRegisterNav,
538→}: AgentDetailColumnProps) {
539→  const { set: expandedItems, toggle: toggleItem } = useToggleSet();
540→  const [selectedItem, setSelectedItem] = useState(0);
541→  const scrollRef = useScrollToSelected(selectedItem);
542→  const detailBodyRef = useAutoScroll<HTMLDivElement>(msg.items.length);
543→  const panelColor = item.team_color ? getTeamColor(item.team_color) : undefined;
544→
545→  const model = msg.model ? shortModel(msg.model) : "";
546→  const modelColor = msg.model ? getModelColor(msg.model) : undefined;
547→  const time = formatExactTime(msg.timestamp);
548→  const hasItems = msg.items.length > 0;
549→
550→  // Check if a deeper panel is open for a given agent_id
551→  const activeAgentId = depth + 1 < panelStack.length ? panelStack[depth + 1].item.agent_id : null;
552→
553→  const handleItemClick = (index: number, clickedItem: DisplayItem) => {
554→    onFocus();
555→    setSelectedItem(index);
556→    if (clickedItem.subagent_messages.length > 0) {
557→      onOpenSubagent(clickedItem);
558→    } else {
559→      toggleItem(index);
560→    }
561→  };
562→
563→  // Expose navigation to parent via callback ref
564→  const navRef = useRef<ColumnNav>({
565→    moveUp: () => {},
566→    moveDown: () => {},
567→    toggle: () => {},
568→    enter: () => {},
569→    itemCount: () => msg.items.length,
570→  });
571→  navRef.current.moveUp = () => setSelectedItem((i) => Math.max(i - 1, 0));
572→  navRef.current.moveDown = () => setSelectedItem((i) => Math.min(i + 1, msg.items.length - 1));
573→  navRef.current.toggle = () => {
574→    const it = msg.items[selectedItem];
575→    if (it) handleItemClick(selectedItem, it);
576→  };
577→  navRef.current.enter = () => {
578→    const it = msg.items[selectedItem];
579→    if (it && it.subagent_messages.length > 0) {
580→      onOpenSubagent(it);
581→    } else if (it) {
582→      toggleItem(selectedItem);
583→    }
584→  };
585→  navRef.current.itemCount = () => msg.items.length;
586→
587→  useLayoutEffect(() => {
588→    onRegisterNav(navRef.current);
589→    return () => onRegisterNav(null);
590→  }, [onRegisterNav]);
591→
592→  return (
593→    <div
594→      className={`agent-panel${isFocused ? " agent-panel--focused" : ""}`}
595→      style={
596→        {
597→          ...(panelColor ? { background: `${panelColor}08` } : {}),
598→          ...style,
599→        } as React.CSSProperties
600→      }
601→      onClick={onFocus}
602→    >
603→      <AgentPanelHeader item={item} panelColor={panelColor} onClose={onClose} />
604→      <div className="agent-panel__content">
605→        <div className="message-detail__header" style={{ borderBottom: "1px solid var(--border)" }}>
606→          <BackButton onClick={onBack} />
607→          <span className="message-detail__title">
608→            {msg.role === "user" ? "User" : msg.role === "claude" ? "Claude" : "System"}
609→          </span>
610→          {model && (
611→            <span style={{ color: modelColor, fontWeight: 600, fontSize: 12 }}>{model}</span>
612→          )}
613→          <span className="message-detail__meta">
614→            {time}
615→            {msg.tokens_raw > 0 && (
616→              <>
617→                {" "}
618→                {"\u00B7"} {formatTokens(msg.tokens_raw)} tok
619→              </>
620→            )}
621→          </span>
622→        </div>
623→        <div className="message-detail__body" ref={detailBodyRef}>
624→          <div className="message-detail__content">
625→            {msg.content && (
626→              <div className="message-detail__text">
627→                <ReactMarkdown>{msg.content}</ReactMarkdown>
628→              </div>
629→            )}
630→            {hasItems && (
631→              <div className="detail-items">
632→                <div className="detail-items__section-label">Items ({msg.items.length})</div>
633→                {msg.items.map((di, idx) => (
634→                  <DetailItem
635→                    key={`${di.item_type}-${di.tool_name}-${di.tool_summary}-${di.duration_ms}`}
636→                    ref={idx === selectedItem ? scrollRef : undefined}
637→                    item={di}
638→                    index={idx}
639→                    isSelected={idx === selectedItem}
640→                    isExpanded={expandedItems.has(idx)}
641→                    isAgentActive={activeAgentId === di.agent_id && !!di.agent_id}
642→                    onToggle={handleItemClick}
643→                    onToggleExpand={toggleItem}
644→                    onSelect={setSelectedItem}
645→                  />
646→                ))}
647→              </div>
648→            )}
649→            {item.subagent_ongoing && (
