  1→import { useMemo } from "react";
  2→import type { SessionInfo } from "../types";
  3→import { shortPath, projectKey, projectDisplayName } from "../lib/format";
  4→import { useScrollToSelected } from "../hooks/useScrollToSelected";
  5→import { RefreshIcon, GitBranchIcon, GitMergeIcon } from "./Icons";
  6→import { OngoingDots } from "./OngoingDots";
  7→
  8→interface ProjectTreeProps {
  9→  sessions: SessionInfo[];
 10→  selectedProject: string | null;
 11→  highlightedIndex?: number;
 12→  isFocused?: boolean;
 13→  onSelectProject: (project: string | null) => void;
 14→  onRefresh: () => void;
 15→  onFocus?: () => void;
 16→  refreshing?: boolean;
 17→  style?: React.CSSProperties;
 18→}
 19→
 20→class ProjectNode {
 21→  constructor(
 22→    public name: string,
 23→    public key: string,
 24→    public sessionCount: number,
 25→    public hasOngoing: boolean,
 26→  ) {}
 27→
 28→  addSession(isOngoing: boolean) {
 29→    this.sessionCount++;
 30→    if (isOngoing) this.hasOngoing = true;
 31→  }
 32→
 33→  static fromSessions(sessions: SessionInfo[]): ProjectNode[] {
 34→    const map = new Map<string, ProjectNode>();
 35→    for (const s of sessions) {
 36→      const key = projectKey(s.path);
 37→      const existing = map.get(key);
 38→      if (existing) {
 39→        existing.addSession(s.is_ongoing);
 40→      } else {
 41→        map.set(
 42→          key,
 43→          new ProjectNode(shortPath(s.cwd) || projectDisplayName(key), key, 1, s.is_ongoing),
 44→        );
 45→      }
 46→    }
 47→    return [...map.values()].toSorted((a, b) => a.name.localeCompare(b.name));
 48→  }
 49→}
 50→
 51→class TreeNode {
 52→  children: TreeNode[] = [];
 53→
 54→  constructor(public node: ProjectNode) {}
 55→
 56→  static cmp(a: TreeNode, b: TreeNode): number {
 57→    return a.node.name.localeCompare(b.node.name);
 58→  }
 59→
 60→  /** Short label relative to a parent key. */
 61→  static childLabel(parentKey: string, childKey: string): string {
 62→    return childKey.slice(parentKey.length).replace(/^-+/, "") || projectDisplayName(childKey);
 63→  }
 64→
 65→  /** Build a tree from flat nodes — child if B.key starts with A.key + "-". */
 66→  static buildTree(nodes: ProjectNode[]): TreeNode[] {
 67→    const sorted = nodes.toSorted((a, b) => a.key.length - b.key.length);
 68→    const roots: TreeNode[] = [];
 69→    const all: TreeNode[] = [];
 70→
 71→    for (const node of sorted) {
 72→      let parent: TreeNode | undefined;
 73→      for (const candidate of all) {
 74→        if (
 75→          node.key.startsWith(candidate.node.key + "-") &&
 76→          (!parent || candidate.node.key.length > parent.node.key.length)
 77→        ) {
 78→          parent = candidate;
 79→        }
 80→      }
 81→
 82→      const tn = new TreeNode(node);
 83→      all.push(tn);
 84→
 85→      if (parent) {
 86→        tn.node = new ProjectNode(
 87→          TreeNode.childLabel(parent.node.key, node.key),
 88→          node.key,
 89→          node.sessionCount,
 90→          node.hasOngoing,
 91→        );
 92→        parent.children.push(tn);
 93→      } else {
 94→        roots.push(tn);
 95→      }
 96→    }
 97→
 98→    roots.sort(TreeNode.cmp);
 99→    for (const r of all) r.children.sort(TreeNode.cmp);
100→    return roots;
101→  }
102→}
103→
104→type WorktreeKind = "worktrees" | "claude-worktrees";
105→
106→class FlatItem {
107→  constructor(
108→    public key: string | null,
109→    public name: string,
110→    public count: number,
111→    public ongoing: boolean,
112→    public depth: number,
113→    public isGroup: boolean,
114→  ) {}
115→
116→  static detectWorktreeKind(parentKey: string, childKey: string): WorktreeKind | null {
117→    const rest = childKey.slice(parentKey.length);
118→    if (rest.startsWith("--claude-worktrees-")) return "claude-worktrees";
119→    if (rest.startsWith("-worktrees-")) return "worktrees";
120→    return null;
121→  }
122→
123→  static worktreeLeafName(parentKey: string, childKey: string, kind: WorktreeKind): string {
124→    const prefixLen =
125→      kind === "claude-worktrees" ? "--claude-worktrees-".length : "-worktrees-".length;
126→    return (
127→      childKey.slice(parentKey.length + prefixLen).replace(/^-+/, "") ||
128→      projectDisplayName(childKey)
129→    );
130→  }
131→
132→  static fromTree(roots: TreeNode[]): FlatItem[] {
133→    const items: FlatItem[] = [];
134→
135→    function walk(nodes: TreeNode[], depth: number, parentKey: string | null) {
136→      for (const tn of nodes) {
137→        items.push(
138→          new FlatItem(
139→            tn.node.key,
140→            tn.node.name,
141→            tn.node.sessionCount,
142→            tn.node.hasOngoing,
143→            depth,
144→            false,
145→          ),
146→        );
147→
148→        // Categorise children into worktree groups and regular
149→        const groups = new Map<WorktreeKind, TreeNode[]>();
150→        const regular: TreeNode[] = [];
151→        for (const child of tn.children) {
152→          const kind =
153→            parentKey !== null || depth === 0
154→              ? FlatItem.detectWorktreeKind(tn.node.key, child.node.key)
155→              : null;
156→          if (kind) {
157→            let list = groups.get(kind);
158→            if (!list) {
159→              list = [];
160→              groups.set(kind, list);
161→            }
162→            list.push(child);
163→          } else {
164→            regular.push(child);
165→          }
166→        }
167→
168→        // Emit worktree group headers + their children
169→        for (const [kind, children] of groups) {
170→          const totalCount = children.reduce((s, c) => s + c.node.sessionCount, 0);
171→          const anyOngoing = children.some((c) => c.node.hasOngoing);
172→          items.push(
173→            new FlatItem(
174→              `__group:${kind}:${tn.node.key}`,
175→              kind,
176→              totalCount,
177→              anyOngoing,
178→              depth + 1,
179→              true,
180→            ),
181→          );
182→          for (const child of children) {
183→            items.push(
184→              new FlatItem(
185→                child.node.key,
186→                FlatItem.worktreeLeafName(tn.node.key, child.node.key, kind),
187→                child.node.sessionCount,
188→                child.node.hasOngoing,
189→                depth + 2,
190→                false,
191→              ),
192→            );
193→            walk(child.children, depth + 3, child.node.key);
194→          }
195→        }
196→
197→        walk(regular, depth + 1, tn.node.key);
198→      }
199→    }
200→
201→    walk(roots, 0, null);
202→    return items;
203→  }
204→}
205→
206→/**
207→ * Returns the ordered list of selectable keys as displayed in the tree.
208→ * Index 0 = null ("All Projects"), then project keys and group keys in tree order.
209→ */
210→export function useProjectKeys(sessions: SessionInfo[]): (string | null)[] {
211→  return useMemo(() => {
212→    const nodes = ProjectNode.fromSessions(sessions);
213→    const tree = TreeNode.buildTree(nodes);
214→    const flat = FlatItem.fromTree(tree);
215→    return [null, ...flat.map((f) => f.key)];
216→  }, [sessions]);
217→}
