219→export function ProjectTree({
220→  sessions,
221→  selectedProject,
222→  highlightedIndex = 0,
223→  isFocused = false,
224→  onSelectProject,
225→  onRefresh,
226→  onFocus,
227→  refreshing,
228→  style,
229→}: ProjectTreeProps) {
230→  const flatItems = useMemo(() => {
231→    const nodes = ProjectNode.fromSessions(sessions);
232→    const tree = TreeNode.buildTree(nodes);
233→    return FlatItem.fromTree(tree);
234→  }, [sessions]);
235→
236→  const scrollRef = useScrollToSelected(highlightedIndex);
237→
238→  const allItems: FlatItem[] = [
239→    {
240→      key: null,
241→      name: "All Projects",
242→      count: sessions.length,
243→      ongoing: false,
244→      depth: 0,
245→      isGroup: false,
246→    },
247→    ...flatItems,
248→  ];
249→
250→  return (
251→    <div
252→      className={`project-tree${isFocused ? " project-tree--focused" : ""}`}
253→      style={style}
254→      onClick={onFocus}
255→    >
256→      <div className="project-tree__header">
257→        <span>Projects</span>
258→        <button
259→          className={`project-tree__refresh${refreshing ? " project-tree__refresh--spinning" : ""}`}
260→          onClick={(e) => {
261→            e.stopPropagation();
262→            onRefresh();
263→          }}
264→          title="Refresh all projects"
265→        >
266→          <RefreshIcon />
267→        </button>
268→      </div>
269→      <div className="project-tree__list">
270→        {allItems.map((item, idx) => {
271→          const isSelected = !item.isGroup && selectedProject === item.key;
272→          const isHighlighted = isFocused && idx === highlightedIndex;
273→          return (
274→            <div
275→              key={item.key ?? "__all__"}
276→              ref={isHighlighted ? scrollRef : undefined}
277→              className={`project-tree__item${isSelected ? " project-tree__item--selected" : ""}${isHighlighted ? " project-tree__item--highlighted" : ""}${item.depth > 0 ? " project-tree__item--child" : ""}${item.isGroup ? " project-tree__item--group" : ""}`}
278→              style={item.depth > 0 ? { paddingLeft: 12 + item.depth * 16 } : undefined}
279→              onClick={item.isGroup ? undefined : () => onSelectProject(item.key)}
280→            >
281→              <span
282→                className="project-tree__name"
283→                title={item.isGroup ? undefined : (item.key ?? undefined)}
284→              >
285→                {item.depth > 0 && <span className="project-tree__branch">{"\u2514"} </span>}
286→                {item.isGroup && (
287→                  <span className="project-tree__group-icon">
288→                    {item.name === "worktrees" ? <GitBranchIcon /> : <GitMergeIcon />}
289→                  </span>
290→                )}
291→                {item.name}
292→              </span>
293→              <span className="project-tree__meta">
294→                {item.ongoing && <OngoingDots count={1} />}
295→                <span className="project-tree__count">{item.count}</span>
296→              </span>
297→            </div>
298→          );
299→        })}
300→      </div>
301→    </div>
302→  );
303→}
