 20→export function App() {
 21→  const [view, setView] = useState<ViewState>("picker");
 22→  const [selectedMessage, setSelectedMessage] = useState(0);
 23→  const [pickerSelectedIndex, setPickerSelectedIndex] = useState(0);
 24→  const [showKeybinds, setShowKeybinds] = useState(true);
 25→  const [animFrame, setAnimFrame] = useState(0);
 26→  const [selectedProject, setSelectedProject] = useState<string | null>(null);
 27→  const [sidebarWidth, setSidebarWidth] = useState(180);
 28→  const [sidebarFocused, setSidebarFocused] = useState(false);
 29→  const [sidebarHighlight, setSidebarHighlight] = useState(0); // index in project list (0 = "All")
 30→  const [showSettings, setShowSettings] = useState(false);
 31→
 32→  const handleSelectProject = useCallback(
 33→    (project: string | null) => {
 34→      setSelectedProject(project);
 35→      setPickerSelectedIndex(0);
 36→      setSidebarFocused(false);
 37→      if (view !== "picker") setView("picker");
 38→    },
 39→    [view],
 40→  );
 41→
 42→  const session = useSession();
 43→  const picker = usePicker(selectedProject);
 44→  const projectKeys = useProjectKeys(picker.allSessions);
 45→
 46→  const { loadSession, loadDebugLog, sessionPath } = session;
 47→  const { discoverSessions } = picker;
 48→
 49→  const {
 50→    set: expandedMessages,
 51→    toggle: toggleMessage,
 52→    clear: clearExpanded,
 53→    addAll: expandMessages,
 54→  } = useToggleSet();
 55→
 56→  // Animation frame for ongoing indicators
 57→  useEffect(() => {
 58→    if (!session.ongoing) return;
 59→    const id = setInterval(() => {
 60→      setAnimFrame((f) => f + 1);
 61→    }, 100);
 62→    return () => clearInterval(id);
 63→  }, [session.ongoing]);
 64→
 65→  // Shared: fetch project dirs and discover sessions
 66→  const loadProjectDirs = useCallback(async () => {
 67→    try {
 68→      const dirs = await invoke<string[]>("get_project_dirs");
 69→      if (dirs.length > 0) {
 70→        discoverSessions(dirs);
 71→      }
 72→    } catch (err) {
 73→      console.error("Failed to get project dirs:", err);
 74→    }
 75→  }, [discoverSessions]);
 76→
 77→  // Auto-discover sessions on mount; show settings if no path configured
 78→  const discoveredRef = useRef(false);
 79→  useEffect(() => {
 80→    if (discoveredRef.current) return;
 81→    discoveredRef.current = true;
 82→    const discover = async () => {
 83→      let hasConfig = false;
 84→      try {
 85→        const settings = await invoke<{ projects_dir: string | null }>("get_settings");
 86→        hasConfig = settings.projects_dir != null;
 87→      } catch {
 88→        // no settings file yet
 89→      }
 90→      if (!hasConfig) {
 91→        setShowSettings(true);
 92→        return;
 93→      }
 94→      loadProjectDirs();
 95→    };
 96→    discover();
 97→  }, [loadProjectDirs]);
 98→
 99→  // Handle session selection from picker
100→  const handleSelectSession = useCallback(
101→    (sessionInfo: SessionInfo) => {
102→      loadSession(sessionInfo.path);
103→      setView("list");
104→      setSelectedMessage(0);
105→      clearExpanded();
106→    },
107→    [loadSession, clearExpanded],
108→  );
109→
110→  // Auto-select newest message (last index) when messages load
111→  useEffect(() => {
112→    if (session.messages.length > 0 && view === "list") {
113→      setSelectedMessage((prev) =>
114→        prev >= session.messages.length ? session.messages.length - 1 : prev,
115→      );
116→    }
117→  }, [session.messages.length, view]);
118→
119→  // Open detail view
120→  const openDetail = useCallback((index: number) => {
121→    setSelectedMessage(index);
122→    setView("detail");
123→  }, []);
124→
125→  // -- Extracted action callbacks for toolbar + keyboard --
126→
127→  const expandAll = useCallback(() => {
128→    const claudeIndices: number[] = [];
129→    session.messages.forEach((msg, i) => {
130→      if (msg.role === "claude") claudeIndices.push(i);
131→    });
132→    expandMessages(claudeIndices);
133→  }, [session.messages, expandMessages]);
134→
135→  const collapseAll = useCallback(() => {
136→    clearExpanded();
137→  }, [clearExpanded]);
138→
139→  // Visual top = newest message = last index (display is reversed)
140→  const jumpToTop = useCallback(() => {
141→    setSelectedMessage(Math.max(session.messages.length - 1, 0));
142→  }, [session.messages.length]);
143→
144→  // Visual bottom = oldest message = index 0
145→  const jumpToBottom = useCallback(() => {
146→    setSelectedMessage(0);
147→  }, []);
148→
149→  const openDebug = useCallback(() => {
150→    if (sessionPath) {
151→      loadDebugLog(sessionPath);
