153→    }
154→  }, [sessionPath, loadDebugLog]);
155→
156→  const openTeams = useCallback(() => {
157→    if (session.teams.length > 0) setView("team");
158→  }, [session.teams.length]);
159→
160→  const goToSessions = useCallback(() => {
161→    setView("picker");
162→  }, []);
163→
164→  const backToList = useCallback(() => {
165→    if (sessionPath) setView("list");
166→  }, [sessionPath]);
167→
168→  const toggleKeybinds = useCallback(() => {
169→    setShowKeybinds((v) => !v);
170→  }, []);
171→
172→  const selectProjectByIndex = useCallback(
173→    (index: number) => {
174→      if (index >= 0 && index < projectKeys.length) {
