176→      }
177→    },
178→    [projectKeys, handleSelectProject],
179→  );
180→
181→  // Keyboard navigation — build keyMap per view
182→  const keyMap: Record<string, () => void> = {};
183→
184→  // Sidebar-focused shortcuts (override main shortcuts when sidebar has focus)
185→  if (sidebarFocused) {
186→    const sidebarDown = () => setSidebarHighlight((i) => Math.min(i + 1, projectKeys.length - 1));
187→    const sidebarUp = () => setSidebarHighlight((i) => Math.max(i - 1, 0));
188→    keyMap["j"] = sidebarDown;
189→    keyMap["ArrowDown"] = sidebarDown;
190→    keyMap["k"] = sidebarUp;
191→    keyMap["ArrowUp"] = sidebarUp;
192→    keyMap["Enter"] = () => selectProjectByIndex(sidebarHighlight);
193→    keyMap["Escape"] = () => setSidebarFocused(false);
194→    keyMap["l"] = () => setSidebarFocused(false);
195→    keyMap["ArrowRight"] = () => setSidebarFocused(false);
196→    keyMap["?"] = toggleKeybinds;
197→  } else {
198→    switch (view) {
199→      case "list": {
200→        const listDown = () => setSelectedMessage((i) => Math.max(i - 1, 0));
201→        const listUp = () =>
202→          setSelectedMessage((i) => Math.min(i + 1, session.messages.length - 1));
203→        keyMap["j"] = listDown;
204→        keyMap["ArrowDown"] = listDown;
205→        keyMap["k"] = listUp;
206→        keyMap["ArrowUp"] = listUp;
207→        keyMap["G"] = jumpToTop;
208→        keyMap["g"] = jumpToBottom;
209→        keyMap["Tab"] = () => toggleMessage(selectedMessage);
210→        keyMap["Enter"] = () => {
211→          if (session.messages.length > 0) openDetail(selectedMessage);
212→        };
213→        keyMap["e"] = expandAll;
214→        keyMap["c"] = collapseAll;
215→        keyMap["t"] = openTeams;
216→        keyMap["d"] = openDebug;
217→        keyMap["q"] = goToSessions;
218→        keyMap["Escape"] = goToSessions;
219→        keyMap["s"] = goToSessions;
