228→        break;
229→      case "picker": {
230→        const pickerDown = () =>
231→          setPickerSelectedIndex((i) => Math.min(i + 1, picker.sessions.length - 1));
232→        const pickerUp = () => setPickerSelectedIndex((i) => Math.max(i - 1, 0));
233→        keyMap["j"] = pickerDown;
234→        keyMap["ArrowDown"] = pickerDown;
235→        keyMap["k"] = pickerUp;
236→        keyMap["ArrowUp"] = pickerUp;
237→        keyMap["Enter"] = () => {
238→          if (picker.sessions[pickerSelectedIndex])
