240→        };
241→        keyMap["q"] = backToList;
242→        keyMap["Escape"] = backToList;
243→        keyMap["?"] = toggleKeybinds;
244→        keyMap["h"] = () => setSidebarFocused(true);
245→        keyMap["ArrowLeft"] = () => setSidebarFocused(true);
246→        break;
247→      }
248→      case "team":
249→        keyMap["q"] = () => setView("list");
250→        keyMap["Escape"] = () => setView("list");
251→        keyMap["?"] = toggleKeybinds;
252→        break;
253→      case "debug":
254→        keyMap["q"] = () => setView("list");
255→        keyMap["Escape"] = () => setView("list");
256→        keyMap["?"] = toggleKeybinds;
