272→  } else if (view === "detail") {
273→    keybindActions["back"] = () => setView("list");
274→  } else if (view === "team") {
275→    keybindActions["back"] = () => setView("list");
276→  } else if (view === "debug") {
277→    keybindActions["back"] = () => setView("list");
278→  }
