import { describe, it, expect } from "vitest";
import { renderHook, act } from "@testing-library/react";
import { useRef } from "react";
import { useAutoScroll } from "./useAutoScroll";

function mockScrollableElement(scrollTop: number, scrollHeight: number, clientHeight: number) {
  const el = document.createElement("div");
  Object.defineProperty(el, "scrollHeight", { value: scrollHeight, configurable: true });
  Object.defineProperty(el, "scrollTop", { value: scrollTop, writable: true, configurable: true });
  Object.defineProperty(el, "clientHeight", { value: clientHeight, configurable: true });
  return el;
}

/** Simulate a scroll event so the hook captures near-bottom state. */
function fireScroll(el: HTMLElement) {
  el.dispatchEvent(new Event("scroll"));
}

describe("useAutoScroll", () => {
  it("returns a ref", () => {
    const { result } = renderHook(() => useAutoScroll(0));
    expect(result.current).toHaveProperty("current");
  });

  it("auto-scrolls when item count increases and was near bottom", () => {
    const { result, rerender } = renderHook(({ count }) => useAutoScroll<HTMLDivElement>(count), {
      initialProps: { count: 1 },
    });

    // scrollTop 400, scrollHeight 500, clientHeight 100 → distance = 0 (at bottom)
    const el = mockScrollableElement(400, 500, 100);
    Object.defineProperty(result.current, "current", { value: el, writable: true });

    // Fire scroll so the hook captures near-bottom state
    act(() => fireScroll(el));

    rerender({ count: 2 });
    expect(el.scrollTop).toBe(500);
  });

  it("does not auto-scroll when user has scrolled up", () => {
    const { result, rerender } = renderHook(({ count }) => useAutoScroll<HTMLDivElement>(count), {
      initialProps: { count: 1 },
    });

    // scrollTop 200, scrollHeight 1000, clientHeight 100 → distance = 700 (far from bottom)
    const el = mockScrollableElement(200, 1000, 100);
    Object.defineProperty(result.current, "current", { value: el, writable: true });

    // Fire scroll so the hook captures NOT near-bottom state
    act(() => fireScroll(el));

    rerender({ count: 2 });
    expect(el.scrollTop).toBe(200);
  });

  it("does not auto-scroll when count stays the same", () => {
    const { result, rerender } = renderHook(({ count }) => useAutoScroll<HTMLDivElement>(count), {
      initialProps: { count: 3 },
    });

    const el = mockScrollableElement(400, 500, 100);
    Object.defineProperty(result.current, "current", { value: el, writable: true });

    act(() => fireScroll(el));

    rerender({ count: 3 });
    expect(el.scrollTop).toBe(400);
  });

  it("works with an existing ref passed in", () => {
    const { result, rerender } = renderHook(
      ({ count }) => {
        const ref = useRef<HTMLDivElement>(null);
        useAutoScroll(count, ref);
        return ref;
      },
      { initialProps: { count: 1 } },
    );

    const el = mockScrollableElement(400, 500, 100);
    Object.defineProperty(result.current, "current", { value: el, writable: true });

    act(() => fireScroll(el));

    rerender({ count: 2 });
    expect(el.scrollTop).toBe(500);
  });

  it("defaults to near-bottom on initial render (no scroll event yet)", () => {
    const { result, rerender } = renderHook(({ count }) => useAutoScroll<HTMLDivElement>(count), {
      initialProps: { count: 1 },
    });

    const el = mockScrollableElement(0, 500, 500);
    Object.defineProperty(result.current, "current", { value: el, writable: true });

    // No scroll event fired — should default to "near bottom" and auto-scroll
    rerender({ count: 2 });
    expect(el.scrollTop).toBe(500);
  });

  it("auto-scrolls even when new content adds significant height", () => {
    const { result, rerender } = renderHook(({ count }) => useAutoScroll<HTMLDivElement>(count), {
      initialProps: { count: 1 },
    });

    // Start at bottom: distance = 500 - 400 - 100 = 0
    const el = mockScrollableElement(400, 500, 100);
    Object.defineProperty(result.current, "current", { value: el, writable: true });

    // User is at bottom — fire scroll to capture state
    act(() => fireScroll(el));

    // Now simulate new content being added: scrollHeight jumps to 2000
    // (the old approach would see distance = 2000-400-100 = 1500 > 150 and NOT scroll)
    Object.defineProperty(el, "scrollHeight", { value: 2000, configurable: true });

    rerender({ count: 2 });
    // Should scroll because near-bottom was captured BEFORE the content grew
    expect(el.scrollTop).toBe(2000);
  });
});

