169→      setSelectedItem((i) => Math.max(i - 1, 0));
170→    } else {
171→      const nav = panelRefs.current.get(focusedColumn - 1);
172→      nav?.moveUp();
173→    }
174→  };
175→  detailKeyMap["j"] = moveDown;
176→  detailKeyMap["ArrowDown"] = moveDown;
177→  detailKeyMap["k"] = moveUp;
178→  detailKeyMap["ArrowUp"] = moveUp;
179→  detailKeyMap["Tab"] = () => {
180→    if (focusedColumn === 0) {
181→      const item = msg.items[selectedItem];
182→      if (item) handleItemClick(selectedItem, item);
183→    } else {
184→      const nav = panelRefs.current.get(focusedColumn - 1);
