199→    }
200→  };
201→
202→  // h/l or ArrowLeft/ArrowRight to switch focused column
203→  detailKeyMap["h"] = () => setFocusedColumn((c) => Math.max(0, c - 1));
204→  detailKeyMap["ArrowLeft"] = () => setFocusedColumn((c) => Math.max(0, c - 1));
205→  detailKeyMap["l"] = () => setFocusedColumn((c) => Math.min(panelStack.length, c + 1));
206→  detailKeyMap["ArrowRight"] = () => setFocusedColumn((c) => Math.min(panelStack.length, c + 1));
