258→          </span>
259→        </div>
260→
261→        <div className="message-detail__body" ref={bodyRef}>
262→          <div className="message-detail__content">
263→            {msg.content && (
264→              <div className="message-detail__text">
265→                <ReactMarkdown>{msg.content}</ReactMarkdown>
266→              </div>
267→            )}
268→            {hasItems && (
269→              <div className="detail-items">
270→                <div className="detail-items__section-label">Items ({msg.items.length})</div>
271→                {msg.items.map((item, idx) => (
272→                  <DetailItem
273→                    key={`${item.item_type}-${item.tool_name}-${item.tool_summary}-${item.duration_ms}`}
274→                    ref={idx === selectedItem ? scrollRef : undefined}
275→                    item={item}
276→                    index={idx}
277→                    isSelected={idx === selectedItem}
278→                    isExpanded={expandedItems.has(idx)}
279→                    isAgentActive={
280→                      panelStack.length > 0 &&
281→                      panelStack[0].item.agent_id === item.agent_id &&
282→                      !!item.agent_id
283→                    }
284→                    onToggle={handleItemClick}
285→                    onToggleExpand={toggleItem}
286→                    onSelect={setSelectedItem}
287→                  />
288→                ))}
289→              </div>
290→            )}
291→            {ongoing && (
292→              <div className="message-detail__ongoing">
293→                <OngoingDots />
294→              </div>
295→            )}
296→          </div>
297→        </div>
298→      </div>
299→
300→      {panelStack.map((entry, depth) => {
301→        const colWidth = columnWidths[depth + 1];
302→        const widthStyle = colWidth ? { flex: `0 0 ${colWidth}px`, maxWidth: colWidth } : undefined;
303→        const isFocused = focusedColumn === depth + 1;
304→
305→        return (
306→          <PanelColumn
307→            key={entry.key}
308→            entry={entry}
309→            depth={depth}
310→            style={widthStyle}
311→            isFocused={isFocused}
312→            panelStack={panelStack}
313→            onOpenDetail={(detailMsg) => openDetailAt(depth, detailMsg)}
314→            onBackToList={() => backToListAt(depth)}
315→            onOpenSubagent={(item) => openSubagentAt(depth, item)}
316→            onClose={() => closeAt(depth)}
317→            onResize={(w) => setColumnWidth(depth, w)}
318→            onFocus={() => setFocusedColumn(depth + 1)}
319→            onRegisterNav={(nav) => registerPanelNav(depth, nav)}
320→          />
321→        );
322→      })}
323→    </div>
324→  );
325→}
326→
327→/* ─── PanelColumn: renders ResizeHandle + either list or detail ─── */
328→
329→interface PanelColumnProps {
330→  entry: PanelEntry;
331→  depth: number;
332→  style?: React.CSSProperties;
333→  isFocused: boolean;
334→  panelStack: PanelEntry[];
335→  onOpenDetail: (msg: DisplayMessage) => void;
336→  onBackToList: () => void;
337→  onOpenSubagent: (item: DisplayItem) => void;
338→  onClose: () => void;
339→  onResize: (width: number) => void;
340→  onFocus: () => void;
341→  onRegisterNav: (nav: ColumnNav | null) => void;
342→}
343→
344→function PanelColumn({
345→  entry,
346→  depth,
347→  style,
348→  isFocused,
349→  panelStack,
350→  onOpenDetail,
351→  onBackToList,
352→  onOpenSubagent,
353→  onClose,
354→  onResize,
355→  onFocus,
356→  onRegisterNav,
357→}: PanelColumnProps) {
358→  return (
359→    <>
360→      <ResizeHandle onResize={onResize} />
361→      {entry.kind === "agent-list" ? (
362→        <AgentListColumn
363→          item={entry.item}
364→          style={style}
365→          isFocused={isFocused}
366→          onOpenDetail={onOpenDetail}
367→          onClose={onClose}
368→          onFocus={onFocus}
369→          onRegisterNav={onRegisterNav}
370→        />
371→      ) : (
372→        <AgentDetailColumn
373→          item={entry.item}
374→          msg={entry.msg}
375→          style={style}
376→          isFocused={isFocused}
377→          depth={depth}
378→          panelStack={panelStack}
379→          onOpenSubagent={onOpenSubagent}
380→          onBack={onBackToList}
381→          onClose={onClose}
382→          onFocus={onFocus}
383→          onRegisterNav={onRegisterNav}
384→        />
385→      )}
386→    </>
387→  );
388→}
389→
390→/* ─── AgentListColumn: shows agent header + message list ─── */
391→
392→interface AgentListColumnProps {
393→  item: DisplayItem;
394→  style?: React.CSSProperties;
395→  isFocused: boolean;
396→  onOpenDetail: (msg: DisplayMessage) => void;
397→  onClose: () => void;
398→  onFocus: () => void;
399→  onRegisterNav: (nav: ColumnNav | null) => void;
400→}
401→
402→function AgentListColumn({
403→  item,
404→  style,
405→  isFocused,
406→  onOpenDetail,
407→  onClose,
408→  onFocus,
409→  onRegisterNav,
410→}: AgentListColumnProps) {
411→  const messages = item.subagent_messages;
412→  const [selectedMsg, setSelectedMsg] = useState(messages.length - 1);
413→  const { set: expandedSet, toggle: toggleMsg } = useToggleSet();
414→  const listRef = useAutoScroll<HTMLDivElement>(messages.length);
415→  const selectedRef = useScrollToSelected(selectedMsg);
416→  const panelColor = item.team_color ? getTeamColor(item.team_color) : undefined;
417→
418→  const handleClick = useCallback(
419→    (index: number) => {
420→      onFocus();
421→      if (selectedMsg === index) {
422→        toggleMsg(index);
423→      } else {
424→        setSelectedMsg(index);
425→      }
426→    },
427→    [selectedMsg, toggleMsg, onFocus],
428→  );
429→
430→  // Expose navigation to parent via callback ref
431→  const navRef = useRef<ColumnNav>({
432→    moveUp: () => setSelectedMsg((i) => Math.max(i - 1, 0)),
433→    moveDown: () => setSelectedMsg((i) => Math.min(i + 1, messages.length - 1)),
434→    toggle: () => toggleMsg(selectedMsg),
435→    enter: () => {
436→      if (messages[selectedMsg]) onOpenDetail(messages[selectedMsg]);
437→    },
438→    itemCount: () => messages.length,
439→  });
440→  navRef.current.moveUp = () => setSelectedMsg((i) => Math.max(i - 1, 0));
441→  navRef.current.moveDown = () => setSelectedMsg((i) => Math.min(i + 1, messages.length - 1));
442→  navRef.current.toggle = () => toggleMsg(selectedMsg);
443→  navRef.current.enter = () => {
444→    if (messages[selectedMsg]) onOpenDetail(messages[selectedMsg]);
445→  };
446→  navRef.current.itemCount = () => messages.length;
447→
448→  // Register/unregister nav on mount/unmount
449→  useLayoutEffect(() => {
450→    onRegisterNav(navRef.current);
451→    return () => onRegisterNav(null);
452→  }, [onRegisterNav]);
453→
454→  const ordered = useMemo(() => {
455→    const indices: number[] = [];
456→    for (let i = 0; i < messages.length; i++) indices.push(i);
457→    return indices;
458→  }, [messages.length]);
459→
460→  return (
461→    <div
462→      className={`agent-panel${isFocused ? " agent-panel--focused" : ""}`}
463→      style={
464→        {
465→          ...(panelColor ? { background: `${panelColor}08` } : {}),
466→          ...style,
467→        } as React.CSSProperties
468→      }
469→      onClick={onFocus}
470→    >
471→      <AgentPanelHeader item={item} panelColor={panelColor} onClose={onClose} />
472→      <div className="agent-panel__content">
473→        <div className="agent-panel__list" ref={listRef}>
474→          {ordered.map((i) => {
475→            const msg = messages[i];
476→            if (msg.role === "compact") {
477→              return (
478→                <div key={i} className="compact-separator">
479→                  <div className="compact-separator__line">
480→                    <span className="compact-separator__rule" />
481→                    <span>{msg.content}</span>
482→                    <span className="compact-separator__rule" />
483→                  </div>
484→                </div>
485→              );
486→            }
487→            const isSelected = i === selectedMsg;
488→            const isExpanded = expandedSet.has(i);
489→            const isLast = i === messages.length - 1;
490→            return (
491→              <MessageItem
492→                key={i}
493→                ref={isSelected ? selectedRef : undefined}
494→                message={msg}
495→                index={i}
496→                isSelected={isSelected}
497→                isExpanded={isExpanded}
498→                isOngoing={isLast && item.subagent_ongoing}
499→                onClick={handleClick}
500→                onOpenDetail={(idx) => onOpenDetail(messages[idx])}
501→              />
502→            );
503→          })}
504→        </div>
505→      </div>
506→    </div>
507→  );
508→}
509→
510→/* ─── AgentDetailColumn: shows a single message's detail items ─── */
511→
512→interface AgentDetailColumnProps {
513→  item: DisplayItem;
514→  msg: DisplayMessage;
515→  style?: React.CSSProperties;
516→  isFocused: boolean;
517→  depth: number;
518→  panelStack: PanelEntry[];
519→  onOpenSubagent: (item: DisplayItem) => void;
520→  onBack: () => void;
521→  onClose: () => void;
522→  onFocus: () => void;
523→  onRegisterNav: (nav: ColumnNav | null) => void;
524→}
