526→function AgentDetailColumn({
527→  item,
528→  msg,
529→  style,
530→  isFocused,
531→  depth,
532→  panelStack,
533→  onOpenSubagent,
534→  onBack,
535→  onClose,
536→  onFocus,
537→  onRegisterNav,
538→}: AgentDetailColumnProps) {
539→  const { set: expandedItems, toggle: toggleItem } = useToggleSet();
540→  const [selectedItem, setSelectedItem] = useState(0);
541→  const scrollRef = useScrollToSelected(selectedItem);
542→  const detailBodyRef = useAutoScroll<HTMLDivElement>(msg.items.length);
543→  const panelColor = item.team_color ? getTeamColor(item.team_color) : undefined;
544→
545→  const model = msg.model ? shortModel(msg.model) : "";
