623→        <div className="message-detail__body" ref={detailBodyRef}>
624→          <div className="message-detail__content">
625→            {msg.content && (
626→              <div className="message-detail__text">
627→                <ReactMarkdown>{msg.content}</ReactMarkdown>
628→              </div>
629→            )}
630→            {hasItems && (
631→              <div className="detail-items">
