641→                    isAgentActive={activeAgentId === di.agent_id && !!di.agent_id}
642→                    onToggle={handleItemClick}
643→                    onToggleExpand={toggleItem}
644→                    onSelect={setSelectedItem}
645→                  />
646→                ))}
