        sessionPath=""
        ongoing={false}
      />,
    );
    expect(screen.getByText("1.50")).toBeInTheDocument();
  });

  it("shows active spinner when ongoing=true", () => {
    render(
      <InfoBar
        meta={makeMeta()}
        gitInfo={null}
        messages={[]}
        sessionTotals={makeTotals()}
        sessionPath=""
        ongoing={true}
      />,
