    expect(screen.getByText(/active/)).toBeInTheDocument();
  });

  it("does not show active spinner when ongoing=false", () => {
    render(
      <InfoBar
        meta={makeMeta()}
        gitInfo={null}
        messages={[]}
        sessionTotals={makeTotals()}
        sessionPath=""
        ongoing={false}
      />,
    );
    expect(screen.queryByText(/active/)).not.toBeInTheDocument();
  });
